def get_db():
    # timeout=15 + busy_timeout make SQLite wait for a lock to clear instead
    # of raising "database is locked" the instant two reruns overlap.
    conn = sqlite3.connect("frenchflow.db", timeout=15)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA busy_timeout = 15000")  # wait up to 15s for a lock
    conn.execute("PRAGMA journal_mode = WAL")     # readers + 1 writer coexist
    return conn

@st.cache_resource
def init_db():
    # @st.cache_resource → this whole function body runs ONCE when the
    # server starts, not on every rerun. That stops the per-click write
    # storm (migrations + seeding) that was causing "database is locked".
    conn = get_db()
    conn.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id            INTEGER PRIMARY KEY AUTOINCREMENT,
            first_name    TEXT    NOT NULL,
            last_name     TEXT    NOT NULL,
            username      TEXT    UNIQUE NOT NULL,
            email         TEXT    UNIQUE NOT NULL,
            password_hash TEXT    NOT NULL,
            is_teacher    INTEGER DEFAULT 0,
            date_joined   TEXT    NOT NULL,
            pages         INTEGER DEFAULT 0,
            char_index    TEXT    DEFAULT '[]'
        )
    """)
    conn.execute("""
        CREATE TABLE IF NOT EXISTS exercise_log (
            id        INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id   INTEGER NOT NULL,
            mood      TEXT    NOT NULL,
            tense     TEXT    NOT NULL,
            correct   INTEGER NOT NULL,
            timestamp TEXT    NOT NULL,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    """)
    # achievement_claims: if an old/incompatible version of this table
    # exists, rebuild it (CREATE IF NOT EXISTS won't fix a bad schema)
    existing_cols = [r[1] for r in
                     conn.execute("PRAGMA table_info(achievement_claims)").fetchall()]
    if existing_cols and not {"user_id", "ach_id", "claimed_at"} <= set(existing_cols):
        conn.execute("DROP TABLE achievement_claims")
    conn.execute("""
        CREATE TABLE IF NOT EXISTS achievement_claims (
            user_id    INTEGER NOT NULL,
            ach_id     TEXT    NOT NULL,
            claimed_at TEXT    NOT NULL,
            PRIMARY KEY (user_id, ach_id)
        )
    """)
    # Migration: lifetime pages earned (current `pages` is the spendable balance)
    try:
        conn.execute("ALTER TABLE users ADD COLUMN pages_earned_total INTEGER DEFAULT 0")
    except sqlite3.OperationalError:
        pass  # column already exists
    # Migration: achievement card equipped as profile background
    try:
        conn.execute("ALTER TABLE users ADD COLUMN equipped_achievement TEXT")
    except sqlite3.OperationalError:
        pass  # column already exists
    # Migration: index character equipped as profile picture
    try:
        conn.execute("ALTER TABLE users ADD COLUMN equipped_character TEXT")
    except sqlite3.OperationalError:
        pass  # column already exists
    # Migration: lifetime counters for exercises and questions completed
    try:
        conn.execute("ALTER TABLE users ADD COLUMN exercises_completed INTEGER DEFAULT 0")
    except sqlite3.OperationalError:
        pass
    try:
        conn.execute("ALTER TABLE users ADD COLUMN questions_completed INTEGER DEFAULT 0")
    except sqlite3.OperationalError:
        pass
    # Migration: persisted dark/light theme preference (0 = light, 1 = dark)
    try:
        conn.execute("ALTER TABLE users ADD COLUMN dark_mode INTEGER DEFAULT 0")
    except sqlite3.OperationalError:
        pass
    # Migration: group exercise_log rows by the exercise they came from, and
    # record the level so devoir matching can check the level range.
    try:
        conn.execute("ALTER TABLE exercise_log ADD COLUMN exercise_id TEXT")
    except sqlite3.OperationalError:
        pass
    try:
        conn.execute("ALTER TABLE exercise_log ADD COLUMN level INTEGER")
    except sqlite3.OperationalError:
        pass
    # Migration: gacha pity counter (rolls since last tier III; at 30 the next
    # roll is a guaranteed tier III)
    try:
        conn.execute("ALTER TABLE users ADD COLUMN pity_counter INTEGER DEFAULT 0")
    except sqlite3.OperationalError:
        pass
    conn.execute("""
        CREATE TABLE IF NOT EXISTS classes (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            class_name  TEXT    NOT NULL,
            class_code  TEXT    UNIQUE NOT NULL,
            teacher_id  INTEGER,
            color       TEXT    DEFAULT '#f7bf8f'
        )
    """)
    conn.execute("""
        CREATE TABLE IF NOT EXISTS class_members (
            class_id INTEGER NOT NULL,
            user_id  INTEGER NOT NULL,
            PRIMARY KEY (class_id, user_id)
        )
    """)
    conn.execute("""
        CREATE TABLE IF NOT EXISTS homework (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            class_id    INTEGER NOT NULL,
            description TEXT    NOT NULL,
            mood        TEXT,
            tense       TEXT,
            due_date    TEXT    NOT NULL,
            level_min   INTEGER DEFAULT 1,
            level_max   INTEGER DEFAULT 2,
            total_req   INTEGER DEFAULT 5,
            FOREIGN KEY (class_id) REFERENCES classes (id)
        )
    """)
    conn.execute("""
        CREATE TABLE IF NOT EXISTS homework_completions (
            hw_id    INTEGER NOT NULL,
            user_id  INTEGER NOT NULL,
            done     INTEGER DEFAULT 0,
            PRIMARY KEY (hw_id, user_id)
        )
    """)
    # Migration: course_code column (teacher-facing label like FSF2DZ)
    try:
        conn.execute("ALTER TABLE classes ADD COLUMN course_code TEXT DEFAULT ''")
    except sqlite3.OperationalError:
        pass
    # Migration: track teacher history so roster shows teachers even after toggle
    try:
        conn.execute("""CREATE TABLE IF NOT EXISTS class_teachers (
            class_id INTEGER NOT NULL,
            user_id  INTEGER NOT NULL,
            PRIMARY KEY (class_id, user_id)
        )""")
    except sqlite3.OperationalError:
        pass
    # Backfill course_code for seeded classes
    conn.execute("UPDATE classes SET course_code='FSF2DZ' WHERE class_code='FSF2DZ' AND (course_code IS NULL OR course_code='')")
    conn.execute("UPDATE classes SET course_code='FIF4UE' WHERE class_code='FIF4UE' AND (course_code IS NULL OR course_code='')")
    # Migration: each devoir gets its own colour, matched on the calendar
    try:
        conn.execute("ALTER TABLE homework ADD COLUMN color TEXT")
    except sqlite3.OperationalError:
        pass  # column already exists
    # ══════════════════════════════════════════════════════════════════
    # SAMPLE DATA — wipe all classes once, then seed 4 populated samples.
    # Guarded by a sentinel in app_meta so it runs a single time. To force
    # a reseed later, bump SEED_VERSION below and restart the server.
    # ══════════════════════════════════════════════════════════════════
    conn.execute("""CREATE TABLE IF NOT EXISTS app_meta (
        key TEXT PRIMARY KEY, value TEXT)""")
    SEED_VERSION = "classes_v2"
    done = conn.execute("SELECT 1 FROM app_meta WHERE key='seed' AND value=?",
                        (SEED_VERSION,)).fetchone()
    if not done:
        # Wipe every existing class and all class-linked data
        conn.execute("DELETE FROM homework_completions")
        conn.execute("DELETE FROM homework")
        conn.execute("DELETE FROM class_members")
        conn.execute("DELETE FROM class_teachers")
        conn.execute("DELETE FROM classes")

        # Resolve teacher + student users by name (fall back gracefully)
        def uid(first, last):
            r = conn.execute(
                "SELECT id FROM users WHERE first_name=? AND last_name=?",
                (first, last)).fetchone()
            return r["id"] if r else None

        park   = uid("Jean-François", "Park")   or 1
        oliver = uid("Oliver", "Horn")          or park
        # Make sure both act as teachers
        for tid in {park, oliver}:
            conn.execute("UPDATE users SET is_teacher=1 WHERE id=?", (tid,))

        # Student pool (by name → id); skip any that don't exist
        student_names = [
            ("Sophie", "Beaumont"), ("Liam", "Nguyen"), ("Amara", "Diallo"),
            ("Ethan", "Kowalski"), ("Chloé", "Martineau"), ("Marcus", "Reid"),
        ]
        students = [i for i in (uid(f, l) for f, l in student_names) if i]

        # Each class: name, invite code, course code, accent colour,
        #   teacher id, list of student ids, list of devoirs.
        # A devoir = (description, mood, tense, days_from_today,
        #             level_min, level_max, total_required, colour)
        seed_classes = [
            {
                "name": "Mme. Tremblay", "code": "FSF2DZ", "course": "FSF2DO",
                "color": "#f7bf8f", "teacher": park,
                "students": students[:5],
                "devoirs": [
                    ("exercices au passé composé",      "Indicatif",  "Passé composé", 4,  2, 3, 4, "#f7bf8f"),
                    ("exercices au subjonctif présent", "Subjonctif", "Présent",       4,  1, 2, 2, "#d8b8ee"),
                    ("exercices au futur simple",       "Indicatif",  "Futur simple",  9,  1, 3, 3, "#a8c8ee"),
                ],
            },
            {
                "name": "M. Park", "code": "ABCXYZ", "course": "FSF3UE",
                "color": "#a7d8a7", "teacher": park,
                "students": students[1:6],
                "devoirs": [
                    ("exercices à l'imparfait",   "Indicatif",   "Imparfait", 2,  2, 3, 5, "#a7d8a7"),
                    ("exercices au conditionnel", "Conditionnel","Présent",   7,  2, 4, 4, "#f2b8cc"),
                ],
            },
            {
                "name": "Mme. Okonkwo", "code": "JKLMNP", "course": "FIF4UZ",
                "color": "#c9a7e8", "teacher": oliver,
                "students": students[:3],
                "devoirs": [
                    ("exercices au plus-que-parfait", "Indicatif",  "Plus-que-parfait", 5,  3, 4, 3, "#c9a7e8"),
                    ("exercices à l'impératif",       "Impératif",  "Présent",          5,  1, 2, 4, "#8fd0e0"),
                    ("exercices au passé simple",     "Indicatif",  "Passé simple",     12, 3, 4, 6, "#f5b585"),
                ],
            },
            {
                "name": "M. Lévesque", "code": "EQNEKW", "course": "ICS3U",
                "color": "#9db8e8", "teacher": oliver,
                "students": students[2:6],
                "devoirs": [
                    ("exercices au futur antérieur", "Indicatif", "Futur antérieur", 3, 3, 4, 4, "#9db8e8"),
                ],
            },
        ]

        for sc in seed_classes:
            conn.execute(
                "INSERT INTO classes (class_name, class_code, course_code, teacher_id, color) VALUES (?,?,?,?,?)",
                (sc["name"], sc["code"], sc["course"], sc["teacher"], sc["color"]))
            cid = conn.execute("SELECT id FROM classes WHERE class_code=?",
                               (sc["code"],)).fetchone()["id"]
            # Teacher = member + class_teachers row
            conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                         (cid, sc["teacher"]))
            conn.execute("INSERT OR IGNORE INTO class_teachers (class_id, user_id) VALUES (?,?)",
                         (cid, sc["teacher"]))
            # Students
            for sid in sc["students"]:
                conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                             (cid, sid))
            # Devoirs + a sample completion per student so progress isn't 0/N
            for desc, mood, tense, in_days, lmin, lmax, req, color in sc["devoirs"]:
                due = (date.today() + timedelta(days=in_days)).isoformat()
                conn.execute(
                    "INSERT INTO homework (class_id, description, mood, tense, due_date, level_min, level_max, total_req, color) VALUES (?,?,?,?,?,?,?,?,?)",
                    (cid, desc, mood, tense, due, lmin, lmax, req, color))
                hw_id = conn.execute(
                    "SELECT id FROM homework WHERE class_id=? ORDER BY id DESC LIMIT 1",
                    (cid,)).fetchone()["id"]
                # Give each student a partial completion (0..req) for realism
                for sid in sc["students"]:
                    conn.execute(
                        "INSERT OR IGNORE INTO homework_completions (hw_id, user_id, done) VALUES (?,?,?)",
                        (hw_id, sid, random.randint(0, req)))

        conn.execute("INSERT OR REPLACE INTO app_meta (key, value) VALUES ('seed', ?)",
                     (SEED_VERSION,))

        # Enroll the first registered account (the usual test login) into
        # every sample class as a student, so the class list isn't empty
        # when you log in. Harmless if that user is also a teacher elsewhere.
        first_user = conn.execute("SELECT id FROM users ORDER BY id LIMIT 1").fetchone()
        if first_user:
            fu = first_user["id"]
            for sc in seed_classes:
                cid = conn.execute("SELECT id FROM classes WHERE class_code=?",
                                   (sc["code"],)).fetchone()["id"]
                conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                             (cid, fu))

    # ── Every class must have a teacher ───────────────────────────────────
    # Legacy/seeded classes were created with teacher_id = NULL. A class
    # should always be owned by whoever created it; for these orphaned
    # seed classes we adopt the first registered user as the teacher so
    # the roster never shows zero teachers. The roster reads from the
    # class_teachers table, so we ensure a row exists there too.
    fallback = conn.execute("SELECT id FROM users ORDER BY id LIMIT 1").fetchone()
    if fallback:
        fb_id = fallback["id"]
        for c in conn.execute("SELECT id, teacher_id FROM classes").fetchall():
            owner = c["teacher_id"]
            if not owner:
                owner = fb_id
                conn.execute("UPDATE classes SET teacher_id=? WHERE id=?",
                             (owner, c["id"]))
            conn.execute("INSERT OR IGNORE INTO class_teachers (class_id, user_id) VALUES (?,?)",
                         (c["id"], owner))
            conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                         (c["id"], owner))
    conn.commit()
    conn.close()

init_db()

