# AUTH HELPERS
# ══════════════════════════════════════════════════════════════════════════════

def hash_password(plain):
    return bcrypt.hashpw(plain.encode(), bcrypt.gensalt()).decode()

def check_password(plain, hashed):
    # The stored hash may be a str (normal) or bytes (if a row was written
    # without decoding). Normalise both sides to bytes for bcrypt.
    if isinstance(plain, str):
        plain = plain.encode()
    if isinstance(hashed, str):
        hashed = hashed.encode()
    try:
        return bcrypt.checkpw(plain, hashed)
    except (ValueError, TypeError):
        return False

def seed_demo_data(conn, user_id):
    """Fake exercise history + currency so the dashboard can be tested.
    Remove this call in create_user() when real data exists."""
    days_back = 110
    # (mood, tense, attempts, starting accuracy, ending accuracy)
    seeds = [
        ("Indicatif",    "Présent",       80, 0.55, 0.92),
        ("Indicatif",    "Passé composé", 55, 0.45, 0.85),
        ("Indicatif",    "Imparfait",     30, 0.40, 0.75),
        ("Indicatif",    "Futur simple",  22, 0.50, 0.80),
        ("Subjonctif",   "Présent",       30, 0.42, 0.78),
        ("Subjonctif",   "Passé",         11, 0.40, 0.70),
        ("Conditionnel", "Présent",       16, 0.50, 0.82),
        ("Impératif",    "Présent",       12, 0.55, 0.85),
    ]
    rows = []
    for mood, tense, n, acc_start, acc_end in seeds:
        for _ in range(n):
            days_ago = random.uniform(0, days_back)
            progress = 1 - (days_ago / days_back)          # 0 = oldest, 1 = newest
            acc = acc_start + (acc_end - acc_start) * progress
            correct = 1 if random.random() < acc else 0
            ts = datetime.now() - timedelta(days=days_ago,
                                            minutes=random.randint(0, 720))
            rows.append((user_id, mood, tense, correct,
                         ts.strftime("%Y-%m-%d %H:%M:%S")))
    conn.executemany(
        "INSERT INTO exercise_log (user_id, mood, tense, correct, timestamp) VALUES (?,?,?,?,?)",
        rows
    )
    # Backdate the join date + give starter currency + a few unlocked
    # characters so the Index (and character achievements) can be tested
    joined = (date.today() - timedelta(days=days_back)).isoformat()
    all_chars = [f"{k}_{t}"
                 for k in ("siakam", "mcrorie", "curie", "laurier", "braille", "jean")
                 for t in (1, 2, 3)]
    demo_chars = json.dumps(random.sample(all_chars, 6))
    conn.execute(
        "UPDATE users SET date_joined = ?, pages = ?, pages_earned_total = ?, char_index = ? WHERE id = ?",
        (joined, random.randint(900, 1300), random.randint(9000, 13000),
         demo_chars, user_id)
    )
    # Auto-join the sample class for testing
    sample = conn.execute("SELECT id FROM classes WHERE class_code = 'FSF2DZ'").fetchone()
    if sample:
        conn.execute(
            "INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
            (sample["id"], user_id)
        )

def create_user(first, last, email, password):
    username = f"{first.lower()}_{last.lower()}"
    hashed   = hash_password(password)
    joined   = str(date.today())
    try:
        conn = get_db()
        cur = conn.execute(
            "INSERT INTO users (first_name, last_name, username, email, password_hash, date_joined) VALUES (?,?,?,?,?,?)",
            (first, last, username, email, hashed, joined)
        )
        seed_demo_data(conn, cur.lastrowid)   # ← demo data for testing
        conn.commit()
        conn.close()
        return True, "Account created!"
    except sqlite3.IntegrityError:
        return False, "An account with that email already exists."

def login_user(email, password):
    conn = get_db()
    row  = conn.execute("SELECT * FROM users WHERE email = ?", (email,)).fetchone()
    conn.close()
    if row and check_password(password, row["password_hash"]):
        return True, dict(row)
    return False, None

def refresh_user():
    """Re-fetch the logged-in user's row so pages/stats are always current."""
    if st.session_state.user:
        conn = get_db()
        row = conn.execute("SELECT * FROM users WHERE id = ?",
                           (st.session_state.user["id"],)).fetchone()
        conn.close()
        if row:
            st.session_state.user = dict(row)
            # Keep the theme preference in sync with the persisted value
            if "dark_mode" in row.keys():
                st.session_state.dark_mode = bool(row["dark_mode"])

# ══════════════════════════════════════════════════════════════════════════════
# SESSION STATE + QUERY PARAMS
# ══════════════════════════════════════════════════════════════════════════════

for key, val in [("page", "login"), ("user", None), ("is_guest", False),
                 ("logged_in", False), ("nav", "profil"), ("profile_view", "dash"),
                 ("selected_class_id", None), ("inspect_student_id", None),
                 ("dark_mode", False)]:
    if key not in st.session_state:
        st.session_state[key] = val

params = st.query_params
if "goto" in params:
    st.session_state.page = params["goto"]
    st.query_params.clear()
    st.rerun()

