def _attempt_login(show_empty_error=False):
    """Shared login logic, called by the Log in button and by pressing Enter
    in the email/password fields (via on_change). On success, sets the session
    so the router routes to the app on the next run."""
    email    = (st.session_state.get("login_email") or "").strip()
    password = st.session_state.get("login_pw") or ""
    if not email or not password:
        # Don't error just because a field was blurred while still empty;
        # only the explicit button press flags missing fields.
        if show_empty_error:
            st.session_state["login_error"] = "Please fill in all fields."
        return
    ok, user = login_user(email, password)
    if ok:
        st.session_state.logged_in = True
        st.session_state.is_guest  = False
        st.session_state.user      = user
        st.session_state.dark_mode = bool(user.get("dark_mode", 0))
        st.session_state.nav       = "profil"
    else:
        st.session_state["login_error"] = "Incorrect email or password."

def render_login():
    st.markdown("## Login")
    st.markdown(
        '<div class="subtitle-row">Don\'t have an account?&nbsp;'
        '<a href="?goto=signup">Create an account</a></div>',
        unsafe_allow_html=True
    )

    st.text_input("Email address", key="login_email", placeholder="",
                  on_change=_attempt_login)
    st.text_input("Password", key="login_pw",
                  type="default" if st.session_state.get("login_show_pw") else "password",
                  placeholder="", on_change=_attempt_login)
    st.checkbox("Show password", key="login_show_pw")

    if st.session_state.get("login_error"):
        st.error(st.session_state.pop("login_error"))

    if st.button("Log in", key="login_btn"):
        _attempt_login(show_empty_error=True)
        st.rerun()

    st.markdown("""
        <div class="or-row">
            <div class="or-line"></div>
            <div class="or-text">or</div>
            <div class="or-line"></div>
        </div>
    """, unsafe_allow_html=True)

    if st.button("Continue as guest", key="guest_btn"):
        st.session_state.is_guest  = True
        st.session_state.logged_in = False
        st.session_state.user      = None
        st.session_state.nav       = "grammaire"
        st.rerun()


def render_signup():
    st.markdown("## Create an account")
    st.markdown(
        '<div class="subtitle-row">Already have an account?&nbsp;'
        '<a href="?goto=login">Log in</a></div>',
        unsafe_allow_html=True
    )

    col1, col2 = st.columns(2)
    with col1:
        st.text_input("First name", key="su_first", placeholder="")
    with col2:
        st.text_input("Last name", key="su_last", placeholder="")

    st.text_input("Email address", key="su_email", placeholder="")

    col3, col4 = st.columns(2)
    with col3:
        st.text_input("Password", key="su_pw",
                      type="default" if st.session_state.get("su_show_pw") else "password",
                      placeholder="")
    with col4:
        st.text_input("Confirm your password", key="su_confirm",
                      type="default" if st.session_state.get("su_show_pw") else "password",
                      placeholder="")

    st.markdown('<p class="helper-text">Use 8 or more characters with a mix of letters and numbers.</p>',
                unsafe_allow_html=True)
    st.checkbox("Show password", key="su_show_pw")

    if st.button("Create an account", key="signup_btn"):
        first_v = st.session_state.get("su_first", "").strip()
        last_v  = st.session_state.get("su_last",  "").strip()
        email_v = st.session_state.get("su_email", "").strip()
        pw_v    = st.session_state.get("su_pw",    "")
        con_v   = st.session_state.get("su_confirm","")

        errors = []
        if not all([first_v, last_v, email_v, pw_v, con_v]):
            errors.append("Please fill in all fields.")
        if pw_v != con_v:
            errors.append("Passwords do not match.")
        if len(pw_v) < 8:
            errors.append("Password must be at least 8 characters.")
        if not any(c.isdigit() for c in pw_v):
            errors.append("Password must contain at least one number.")

        if errors:
            for e in errors:
                st.error(e)
        else:
            ok, msg = create_user(first_v, last_v, email_v, pw_v)
            if ok:
                st.success(f"{msg} You can now log in.")
                st.session_state.page = "login"
                st.rerun()
            else:
                st.error(msg)

