def get_tense_counts(user_id, mood):
    conn = get_db()
    rows = conn.execute(
        "SELECT tense, COUNT(*) AS n FROM exercise_log WHERE user_id=? AND mood=? GROUP BY tense",
        (user_id, mood)).fetchall()
    conn.close()
    return {r["tense"]: r["n"] for r in rows}

def get_total_exercises(user_id):
    conn = get_db()
    n = conn.execute("SELECT COUNT(*) FROM exercise_log WHERE user_id=?",
                     (user_id,)).fetchone()[0]
    conn.close()
    return n

MOOD_ABBREV = {"Indicatif": "Ind.", "Subjonctif": "Subj.",
               "Conditionnel": "Cond.", "Impératif": "Imp."}

# Permanent colour per (mood, tense) series: assigned once, in MOODS order,
# so a tense always keeps its colour no matter what else is selected.
SERIES_ORDER = [f"{MOOD_ABBREV[m]} {t}" for m in MOODS for t in MOODS[m]]
SERIES_COLOR = {label: CHART_PALETTE[i % len(CHART_PALETTE)]
                for i, label in enumerate(SERIES_ORDER)}

def get_chart_data(user_id, pairs, days):
    """Cumulative accuracy (%) per day for each selected (mood, tense) pair.
    Pairs can span multiple moods; each series is labelled 'Abbrev Tense'."""
    if not pairs:
        return pd.DataFrame()
    conn = get_db()
    clause = " OR ".join(["(mood=? AND tense=?)"] * len(pairs))
    q = f"""SELECT mood, tense, correct, timestamp FROM exercise_log
            WHERE user_id=? AND ({clause})"""
    args = [user_id]
    for mood, tense in pairs:
        args += [mood, tense]
    if days is not None:
        q += " AND timestamp >= ?"
        args.append((datetime.now() - timedelta(days=days)).strftime("%Y-%m-%d %H:%M:%S"))
    df = pd.read_sql_query(q, conn, params=args)
    conn.close()
    if df.empty:
        return df

    df["Temps"] = df["mood"].map(MOOD_ABBREV) + " " + df["tense"]
    df["day"]   = pd.to_datetime(df["timestamp"]).dt.normalize()
    daily = (df.groupby(["Temps", "day"])["correct"]
               .agg(corrects="sum", attempts="count").reset_index()
               .sort_values("day"))
    daily["cum_correct"]  = daily.groupby("Temps")["corrects"].cumsum()
    daily["cum_attempts"] = daily.groupby("Temps")["attempts"].cumsum()
    daily["Précision"]    = (daily["cum_correct"] / daily["cum_attempts"] * 100).round(1)
    return daily.rename(columns={"day": "Jour"})

def get_class_chart_data(student_ids, days):
    """Average cumulative accuracy per day across all students, one line = one tense."""
    if not student_ids:
        return pd.DataFrame()
    conn = get_db()
    placeholders = ",".join("?" * len(student_ids))
    q = f"""SELECT user_id, mood, tense, correct, timestamp
            FROM exercise_log
            WHERE user_id IN ({placeholders})"""
    args = list(student_ids)
    if days is not None:
        q += " AND timestamp >= ?"
        args.append((datetime.now() - timedelta(days=days)).strftime("%Y-%m-%d %H:%M:%S"))
    df = pd.read_sql_query(q, conn, params=args)
    conn.close()
    if df.empty:
        return df

    df["Temps"] = df["mood"].map(MOOD_ABBREV) + " " + df["tense"]
    df["day"]   = pd.to_datetime(df["timestamp"]).dt.normalize()

    # Per-student cumulative accuracy per day per tense
    daily = (df.groupby(["user_id", "Temps", "day"])["correct"]
               .agg(corrects="sum", attempts="count").reset_index()
               .sort_values("day"))
    daily["cum_correct"]  = daily.groupby(["user_id","Temps"])["corrects"].cumsum()
    daily["cum_attempts"] = daily.groupby(["user_id","Temps"])["attempts"].cumsum()
    daily["accuracy"]     = daily["cum_correct"] / daily["cum_attempts"] * 100

    # Average across students who have data for that tense on that day
    avg = (daily.groupby(["Temps","day"])["accuracy"]
                .mean().round(1).reset_index()
                .rename(columns={"accuracy":"Précision","day":"Jour"}))
    return avg


