def french_date(iso_str):
    d = datetime.strptime(iso_str, "%Y-%m-%d").date()
    return f"{d.day} {MONTHS_FR[d.month - 1]}, {d.year}"

def membership_age(iso_str):
    d = datetime.strptime(iso_str, "%Y-%m-%d").date()
    days = (date.today() - d).days
    if days < 30:
        return f"{days} jour{'s' if days != 1 else ''}"
    months, rem = divmod(days, 30)
    out = f"{months} mois"
    if rem:
        out += f" et {rem} jour{'s' if rem != 1 else ''}"
    return out

def checkbox_color_css():
    """Each tense's checkbox takes its permanent line colour when checked,
    acting as the chart legend. Keys are index-based (cb_{mood_i}_{tense_i})
    because tense names contain spaces/accents that break CSS selectors."""
    rules = []
    for mi, mood in enumerate(MOODS):
        for ti, tense in enumerate(MOODS[mood]):
            color = SERIES_COLOR[f"{MOOD_ABBREV[mood]} {tense}"]
            rules.append(
                f'.st-key-cb_{mi}_{ti} label:has(input:checked) > '
                f'span:first-of-type {{ background-color: {color} !important; '
                f'border-color: {color} !important; }}'
            )
    return "<style>" + "\n".join(rules) + "</style>"

def render_dashboard_view(user):
    st.markdown('<h1 class="dash-title">Tableau de bord</h1>', unsafe_allow_html=True)
    total = get_total_exercises(user["id"])
    st.markdown(f'<div class="dash-sub">Exercices complétés: {total}</div>',
                unsafe_allow_html=True)
    st.markdown('<hr class="dash-rule">', unsafe_allow_html=True)
    st.markdown(checkbox_color_css(), unsafe_allow_html=True)

    # ── Mood tabs: tense pickers only. Selections from ALL moods feed
    #    the single shared chart below. Coloured checkboxes = legend. ──
    tabs = st.tabs(list(MOODS.keys()))
    for mi, (tab, mood) in enumerate(zip(tabs, MOODS.keys())):
        with tab:
            counts = get_tense_counts(user["id"], mood)
            tense_cols = st.columns(2)
            for ti, tense in enumerate(MOODS[mood]):
                n = counts.get(tense, 0)
                key = f"cb_{mi}_{ti}"
                if key not in st.session_state:
                    st.session_state[key] = False
                with tense_cols[ti % 2]:
                    st.checkbox(f"{tense}: {n}", key=key)

    # Gather every checked (mood, tense) pair across all moods
    selected_pairs = [
        (mood, tense)
        for mi, mood in enumerate(MOODS)
        for ti, tense in enumerate(MOODS[mood])
        if st.session_state.get(f"cb_{mi}_{ti}")
    ]

    st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)

    # ── Shared chart ──────────────────────────────────────────────────
    range_label = st.session_state.get("range_global", "1M")
    days = TIME_RANGES[range_label]
    data = get_chart_data(user["id"], selected_pairs, days)

    # X-axis window for the empty frame (and consistent framing in general)
    end = pd.Timestamp(datetime.now().date())
    if days is not None:
        start = end - pd.Timedelta(days=days)
    else:
        start = pd.Timestamp(user["date_joined"])

    y_axis = alt.Y("Précision:Q",
                   scale=alt.Scale(domain=[0, 100]),
                   axis=alt.Axis(title=None,
                                 values=[0, 25, 50, 75, 100],
                                 labelExpr="datum.value + '%'"))
    fr_months = ("['Jan','Fév','Mar','Avr','Mai','Jun',"
                 "'Jul','Aoû','Sep','Oct','Nov','Déc']"
                 "[month(datum.value)]"
                 " + ' ' + timeFormat(datum.value, '%d')")
    x_axis_kwargs = dict(title=None, labelExpr=fr_months, grid=False)

    def style_chart(c):
        """Soft light look, or a matching dark surface when dark mode is on."""
        dark = bool(st.session_state.get("dark_mode"))
        bg   = "#1c1f26" if dark else "#ffffff"
        lab  = "#aab0bd" if dark else "#777"
        grid = "#2c313b" if dark else "#e3e3e3"
        dom  = "#3a3f49" if dark else "#cccccc"
        return (
            c.properties(height=260, background=bg,
                         padding={"left": 10, "right": 10,
                                  "top": 10, "bottom": 10})
             .configure_view(strokeWidth=0)
             .configure_axis(labelFont="Dongle", labelFontSize=22,
                             labelColor=lab, gridColor=grid,
                             domainColor=dom, tickColor=dom)
        )

    if data.empty:
        # Empty graph frame: same axes, no lines
        empty_df = pd.DataFrame({"Jour": [start, end],
                                 "Précision": [None, None]})
        chart = style_chart(
            alt.Chart(empty_df)
            .mark_line()
            .encode(
                x=alt.X("Jour:T",
                        scale=alt.Scale(domain=[start, end]),
                        axis=alt.Axis(**x_axis_kwargs)),
                y=y_axis,
            )
        )
    else:
        # Fixed colours: domain/range pinned to the permanent mapping,
        # so adding/removing tenses never reshuffles existing colours.
        # No legend — the coloured checkboxes above identify each line.
        present = [s for s in SERIES_ORDER
                   if s in set(data["Temps"].unique())]
        color_scale = alt.Scale(domain=present,
                                range=[SERIES_COLOR[s] for s in present])

        chart = style_chart(
            alt.Chart(data)
            .mark_line(strokeWidth=3.5, interpolate="monotone",
                       strokeCap="round", strokeJoin="round")
            .encode(
                x=alt.X("Jour:T",
                        scale=alt.Scale(domain=[start, end]),
                        axis=alt.Axis(**x_axis_kwargs)),
                y=y_axis,
                color=alt.Color("Temps:N",
                                scale=color_scale,
                                legend=None),
                tooltip=["Temps", alt.Tooltip("Jour:T", format="%d %b %Y", formatType="time"),
                         alt.Tooltip("Précision:Q", format=".1f")],
            )
        )
    # theme=None stops Streamlit injecting its own (dark) chart theme
    st.altair_chart(chart, use_container_width=True, theme=None)

    # X-axis range control, centred under the chart
    _, mid, _ = st.columns([1, 2.6, 1])
    with mid:
        st.segmented_control(
            "Période", list(TIME_RANGES.keys()),
            default="1M", key="range_global",
            label_visibility="collapsed",
        )

