# (key, display name, condition kind, [tier I, II, III thresholds])
ACH_ROWS = [
    ("bienvenue",    "Bienvenue !",            "age",               [0, 14, 60]),
    ("pyro",         "Pyrotechnicien",         "meta",              [5, 15, 25]),
    ("indicatif",    "Maître de l'indicatif",  "mood:Indicatif",    [10, 25, 100]),
    ("subjonctif",   "Maître du subjonctif",   "mood:Subjonctif",   [10, 25, 100]),
    ("conditionnel", "Maître du conditionnel", "mood:Conditionnel", [10, 25, 100]),
    ("imperatif",    "Maître de l'impératif",  "mood:Impératif",    [10, 25, 100]),
    # Character cards — unlocked via the gacha index (entries like "siakam_2")
    ("siakam",  "Pascal Siakam",   "char", [1, 2, 3]),
    ("mcrorie", "Carolyn McRorie",  "char", [1, 2, 3]),
    ("curie",   "Marie Curie",      "char", [1, 2, 3]),
    ("laurier", "Wilfrid Laurier",  "char", [1, 2, 3]),
    ("braille", "Louis Braille",    "char", [1, 2, 3]),
    ("jean",    "Michaëlle Jean",   "char", [1, 2, 3]),
]
TIER_REWARD = {1: 300, 2: 1000, 3: 2500}
ROMAN = {1: "I", 2: "II", 3: "III"}
MOOD_PREP = {"Indicatif": "à l'indicatif", "Subjonctif": "au subjonctif",
             "Conditionnel": "au conditionnel", "Impératif": "à l'impératif"}

def ach_image(key, tier):
    return f"static/achievements/{key}_{tier}.png"

def ach_desc(kind, name, tier, threshold):
    if kind == "age":
        return ("Créez votre compte" if threshold == 0
                else f"Inscrit depuis {threshold} jours")
    if kind == "meta":
        return f"Débloquez {threshold} succès"
    if kind.startswith("mood:"):
        mood = kind.split(":")[1]
        return f"Répondez correctement à {threshold} questions {MOOD_PREP[mood]}"
    return f"Débloquez la variation {ROMAN[tier]} de {name}"

def compute_unlocks(user):
    """Returns {ach_id: bool}. The meta row counts the other unlocked
    achievements, so it's computed in a second pass."""
    conn = get_db()
    rows = conn.execute(
        "SELECT mood, COUNT(*) AS n FROM exercise_log "
        "WHERE user_id=? AND correct=1 GROUP BY mood",
        (user["id"],)).fetchall()
    conn.close()
    mood_counts = {r["mood"]: r["n"] for r in rows}
    age_days = (date.today()
                - datetime.strptime(user["date_joined"], "%Y-%m-%d").date()).days
    try:
        chars = json.loads(user["char_index"] or "[]")
    except (json.JSONDecodeError, TypeError):
        chars = []

    unlocks = {}
    for key, name, kind, thresholds in ACH_ROWS:
        if kind == "meta":
            continue
        for tier, t in enumerate(thresholds, start=1):
            if kind == "age":
                ok = age_days >= t
            elif kind.startswith("mood:"):
                ok = mood_counts.get(kind.split(":")[1], 0) >= t
            else:  # char — gacha index entries, e.g. "siakam_2"
                ok = f"{key}_{tier}" in chars
            unlocks[f"{key}_{tier}"] = ok

    base_count = sum(unlocks.values())
    meta = next(r for r in ACH_ROWS if r[2] == "meta")
    for tier, t in enumerate(meta[3], start=1):
        unlocks[f"{meta[0]}_{tier}"] = base_count >= t
    return unlocks

def get_claims(user_id):
    conn = get_db()
    rows = conn.execute("SELECT ach_id FROM achievement_claims WHERE user_id=?",
                        (user_id,)).fetchall()
    conn.close()
    return {r["ach_id"] for r in rows}

def claim_achievement(user_id, ach_id, reward):
    conn = get_db()
    try:
        conn.execute(
            "INSERT INTO achievement_claims (user_id, ach_id, claimed_at) VALUES (?,?,?)",
            (user_id, ach_id, datetime.now().strftime("%Y-%m-%d %H:%M:%S")))
        conn.execute(
            "UPDATE users SET pages = pages + ?, pages_earned_total = pages_earned_total + ? WHERE id=?",
            (reward, reward, user_id))
        conn.commit()
    except sqlite3.IntegrityError:
        pass  # already claimed — never pay twice
    conn.close()

def equip_achievement(user_id, ach_id):
    conn = get_db()
    conn.execute("UPDATE users SET equipped_achievement=? WHERE id=?",
                 (ach_id, user_id))
    conn.commit()
    conn.close()

def succes_card_css(unlocks, selected):
    """Per-card CSS: background image from static serving, dimming for
    locked cards, ✓ badge for unlocked, highlight for the selected card."""
    rules = []
    for key, name, kind, thresholds in ACH_ROWS:
        for tier in (1, 2, 3):
            aid = f"{key}_{tier}"
            url = f"/app/static/achievements/{key}_{tier}.png"
            base = f".st-key-card_{aid} .stButton > button"
            rules.append(f".st-key-card_{aid} {{ position: relative; }}")
            # Streamlit shrink-wraps button containers — force them to fill
            # the column so the card renders at full size
            rules.append(
                f".st-key-card_{aid}, .st-key-card_{aid} .stButton "
                f"{{ width: 100% !important; }}")
            rules.append(
                f"{base} {{ background-image:url('{url}'); background-size:cover; "
                f"background-position:center; width:100% !important; aspect-ratio:1.9; "
                f"height:auto !important; min-height:0 !important; color:transparent !important; "
                f"border-radius:12px !important; border:1.5px solid #d3d8e6 !important; "
                f"box-shadow:0 1px 4px rgba(120,130,160,0.10) !important; }}")
            if not unlocks[aid]:
                rules.append(f"{base} {{ filter:grayscale(0.45); opacity:0.38; }}")
            else:
                rules.append(
                    f".st-key-card_{aid} .stButton::after {{ content:'✓'; position:absolute; "
                    f"top:9px; right:9px; width:26px; height:26px; background:#b9ecb2; "
                    f"color:#ffffff; border-radius:7px; display:flex; align-items:center; "
                    f"justify-content:center; font-weight:700; pointer-events:none; }}")
            if selected == aid:
                rules.append(f"{base} {{ border:3px solid #8fa8d8 !important; opacity:1; }}")
    return "<style>" + "\n".join(rules) + "</style>"

def render_succes_view(user):
    unlocks = compute_unlocks(user)
    claims  = get_claims(user["id"])

    st.markdown('<h1 class="dash-title">Succès</h1>', unsafe_allow_html=True)
    st.markdown(f'<div class="dash-sub">Nombre de succès: {sum(unlocks.values())}</div>',
                unsafe_allow_html=True)
    st.markdown('<hr class="dash-rule">', unsafe_allow_html=True)

    sel = st.session_state.get("sel_ach")
    if sel is not None and sel not in unlocks:
        sel = None

    st.markdown(succes_card_css(unlocks, sel), unsafe_allow_html=True)

    # Card grid — scrollable; grows taller when no detail panel is open
    with st.container(height=380 if sel else 560, border=False):
        for key, name, kind, thresholds in ACH_ROWS:
            cols = st.columns(3)
            for tier, col in zip((1, 2, 3), cols):
                aid = f"{key}_{tier}"
                with col:
                    if st.button(" ", key=f"card_{aid}"):
                        st.session_state.sel_ach = None if sel == aid else aid
                        st.rerun()

    # Detail panel — only when a card is selected
    if sel:
        key, tier = sel.rsplit("_", 1)
        tier = int(tier)
        row = next(r for r in ACH_ROWS if r[0] == key)
        _, name, kind, thresholds = row

        st.markdown('<hr class="dash-rule">', unsafe_allow_html=True)
        c1, c2 = st.columns([1.1, 1.5], gap="medium")
        with c1:
            st.image(ach_image(key, tier), use_container_width=True)
        with c2:
            st.markdown(
                f'<div class="ach-name">{name} {ROMAN[tier]}</div>'
                f'<div class="ach-desc">{ach_desc(kind, name, tier, thresholds[tier-1])}</div>',
                unsafe_allow_html=True)
            if unlocks[sel]:
                b1, b2, b3 = st.columns([1.15, 1, 0.7])
                with b1:
                    if sel in claims:
                        st.button(f"📚 {TIER_REWARD[tier]:,} ✓", key="claim_btn",
                                  disabled=True)
                    elif st.button(f"📚 {TIER_REWARD[tier]:,}", key="claim_btn"):
                        claim_achievement(user["id"], sel, TIER_REWARD[tier])
                        st.rerun()
                with b2:
                    if user.get("equipped_achievement") == sel:
                        st.button("Équipé", key="equip_btn", disabled=True)
                    elif st.button("Équiper", key="equip_btn"):
                        equip_achievement(user["id"], sel)
                        st.rerun()
                with b3:
                    if st.button("Fermer", key="close_ach"):
                        st.session_state.sel_ach = None
                        st.rerun()
            else:
                # Locked: no claim/equip — just the condition text + close
                _, b3 = st.columns([2.3, 0.7])
                with b3:
                    if st.button("Fermer", key="close_ach"):
                        st.session_state.sel_ach = None
                        st.rerun()

