def get_user_classes(user_id):
    conn = get_db()
    rows = conn.execute("""
        SELECT c.* FROM classes c
        JOIN class_members m ON m.class_id = c.id
        WHERE m.user_id = ?
        ORDER BY c.id
    """, (user_id,)).fetchall()
    conn.close()
    return [dict(r) for r in rows]

def join_class(user_id, code):
    conn = get_db()
    row = conn.execute("SELECT id FROM classes WHERE class_code = ?",
                        (code.strip().upper(),)).fetchone()
    if not row:
        conn.close()
        return False, "Code de classe invalide."
    already = conn.execute(
        "SELECT 1 FROM class_members WHERE class_id = ? AND user_id = ?",
        (row["id"], user_id)
    ).fetchone()
    if already:
        conn.close()
        return False, "Vous êtes déjà membre de cette classe."
    conn.execute("INSERT INTO class_members (class_id, user_id) VALUES (?,?)",
                  (row["id"], user_id))
    conn.commit()
    conn.close()
    return True, "Classe rejointe !"

def join_class_as_teacher(teacher_id, code):
    """Add a teacher as a co-teacher of an existing class."""
    conn = get_db()
    row = conn.execute("SELECT id, teacher_id FROM classes WHERE class_code = ?",
                        (code.strip().upper(),)).fetchone()
    if not row:
        conn.close()
        return False, "Code de classe invalide."
    already = conn.execute(
        "SELECT 1 FROM class_members WHERE class_id = ? AND user_id = ?",
        (row["id"], teacher_id)
    ).fetchone()
    if already:
        conn.close()
        return False, "Vous êtes déjà dans cette classe."
    # Add as member
    conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                  (row["id"], teacher_id))
    conn.execute("INSERT OR IGNORE INTO class_teachers (class_id, user_id) VALUES (?,?)",
                  (row["id"], teacher_id))
    # If no primary teacher set, claim the slot
    if not row["teacher_id"]:
        conn.execute("UPDATE classes SET teacher_id = ? WHERE id = ?",
                     (teacher_id, row["id"]))
    conn.commit()
    conn.close()
    return True, "Classe rejointe en tant qu'enseignant !"

def generate_class_code():
    """Generate a unique 6-character alphanumeric class code."""
    import random, string
    conn = get_db()
    while True:
        code = "".join(random.choices(string.ascii_uppercase + string.digits, k=6))
        exists = conn.execute("SELECT 1 FROM classes WHERE class_code=?", (code,)).fetchone()
        if not exists:
            conn.close()
            return code

def create_class(teacher_id, class_name, course_code):
    """Create a new class owned by the teacher. Returns (True, class_code) or (False, error)."""
    if not class_name.strip():
        return False, "Le nom du cours est requis."
    join_code = generate_class_code()
    # Pick a random accent colour from the palette
    import random
    color = random.choice(["#f7bf8f", "#a7d8a7", "#c9a7e8", "#9db8e8", "#f7c4c4"])
    conn = get_db()
    conn.execute(
        "INSERT INTO classes (class_name, class_code, course_code, teacher_id, color) VALUES (?,?,?,?,?)",
        (class_name.strip(), join_code, course_code.strip().upper(), teacher_id, color)
    )
    # Also add the teacher as a member so they can see the class
    class_id = conn.execute("SELECT id FROM classes WHERE class_code=?", (join_code,)).fetchone()["id"]
    conn.execute("INSERT OR IGNORE INTO class_members (class_id, user_id) VALUES (?,?)",
                 (class_id, teacher_id))
    conn.execute("INSERT OR IGNORE INTO class_teachers (class_id, user_id) VALUES (?,?)",
                 (class_id, teacher_id))
    conn.commit()
    conn.close()
    return True, join_code

def delete_class(teacher_id, class_id):
    """Permanently delete a class and all related data. Only the owning teacher may do this."""
    conn = get_db()
    row = conn.execute("SELECT teacher_id FROM classes WHERE id=?", (class_id,)).fetchone()
    if not row:
        conn.close()
        return False, "Classe introuvable."
    if row["teacher_id"] != teacher_id:
        conn.close()
        return False, "Vous n'êtes pas autorisé à supprimer cette classe."
    conn.execute("DELETE FROM homework_completions WHERE hw_id IN (SELECT id FROM homework WHERE class_id=?)", (class_id,))
    conn.execute("DELETE FROM homework WHERE class_id=?", (class_id,))
    conn.execute("DELETE FROM class_members WHERE class_id=?", (class_id,))
    conn.execute("DELETE FROM class_teachers WHERE class_id=?", (class_id,))
    conn.execute("DELETE FROM classes WHERE id=?", (class_id,))
    conn.commit()
    conn.close()
    return True, "Classe supprimée."

