def render_calendar(year, month, hw_list):
    """Calendar for the given month. Each devoir paints its due date in the
    devoir's own colour — the same colour as its card — so the user can
    match card to date at a glance. Multiple devoirs due the same day show
    a split-colour circle plus one dot per devoir."""
    import calendar
    cal = calendar.monthcalendar(year, month)
    today = date.today()

    due_map = {}  # day -> [colours of devoirs due that day]
    for h in hw_list:
        try:
            d = date.fromisoformat(h["due_date"])
        except (ValueError, TypeError):
            continue
        if d.year == year and d.month == month:
            due_map.setdefault(d.day, []).append(h.get("color") or "#f7bf8f")

    def circle_bg(colors):
        if len(colors) == 1:
            return colors[0]
        seg = 100 / len(colors)
        stops = ", ".join(f"{c} {i*seg:.0f}%, {c} {(i+1)*seg:.0f}%"
                          for i, c in enumerate(colors))
        return f"linear-gradient(135deg, {stops})"

    days_fr = ["LUN", "MAR", "MER", "JEU", "VEN", "SAM", "DIM"]
    month_name = MONTHS_FR[month - 1].upper()

    header = f'<div class="cal-month">{month_name} {year}</div>'
    dow_row = "".join(f'<div class="cal-dow {"cal-dow-weekend" if i >= 5 else ""}">{d}</div>'
                      for i, d in enumerate(days_fr))
    cells = ""
    for week in cal:
        for day in week:
            if day == 0:
                cells += '<div class="cal-cell"></div>'
                continue
            d = date(year, month, day)
            is_today = d == today
            colors = due_map.get(day)
            if colors:
                # Due date: circle in the devoir's colour(s). If it's also
                # today, a lavender ring marks it.
                ring = "border:2px solid #8fa8d8;" if is_today else ""
                inner = (f'<span style="background:{circle_bg(colors)};{ring}">'
                         f'{day}</span>')
                dots = ('<div class="cal-dots">'
                        + "".join(f'<div class="cal-dot" style="background:{c}"></div>'
                                  for c in colors)
                        + "</div>")
                cells += f'<div class="cal-cell cal-due">{inner}{dots}</div>'
            elif is_today:
                cells += f'<div class="cal-cell cal-today"><span>{day}</span></div>'
            else:
                cells += f'<div class="cal-cell">{day}</div>'

    return f"""
    <div class="cal-wrap">
        {header}
        <div class="cal-grid">
            {dow_row}
            {cells}
        </div>
    </div>
    """

