def get_homework_progress(hw_id, class_id):
    """Return list of {first_name, last_name, done, total_req} for every student in the class."""
    conn = get_db()
    rows = conn.execute("""
        SELECT u.first_name, u.last_name,
               COALESCE(hc.done, 0) AS done,
               h.total_req
        FROM class_members cm
        JOIN users u ON u.id = cm.user_id
        JOIN homework h ON h.id = ?
        LEFT JOIN homework_completions hc ON hc.hw_id = ? AND hc.user_id = u.id
        WHERE cm.class_id = ?
          AND u.id NOT IN (SELECT user_id FROM class_teachers WHERE class_id = ?)
        ORDER BY u.last_name, u.first_name
    """, (hw_id, hw_id, class_id, class_id)).fetchall()
    conn.close()
    return [dict(r) for r in rows]

def update_homework(hw_id, mood, tense, quantity, level_min, level_max, due_date):
    conn = get_db()
    desc = f"exercice{'s' if quantity > 1 else ''} au {tense.lower()}"
    color = {"Indicatif": "#f5c89a", "Subjonctif": "#c9b8e8",
             "Conditionnel": "#a8d8c8", "Impératif": "#e8a8b8"}.get(mood, "#ccd7f0")
    conn.execute("""
        UPDATE homework
        SET description=?, mood=?, tense=?, due_date=?,
            level_min=?, level_max=?, total_req=?, color=?
        WHERE id=?
    """, (desc, mood, tense, due_date, level_min, level_max, quantity, color, hw_id))
    conn.commit()
    conn.close()

def delete_homework(hw_id):
    conn = get_db()
    conn.execute("DELETE FROM homework_completions WHERE hw_id=?", (hw_id,))
    conn.execute("DELETE FROM homework WHERE id=?", (hw_id,))
    conn.commit()
    conn.close()


@st.dialog("Assigner un devoir")
def _dialog_assign_homework(user, class_id):
    if st.session_state.get("hw_dialog_error"):
        st.error(st.session_state.pop("hw_dialog_error"))

    mood     = st.selectbox("Type de conjugaison", list(MOODS.keys()), key="hw_mood")
    tense    = st.selectbox("Temps", MOODS[mood], key="hw_tense")
    quantity = st.number_input("Nombre d'exercices", min_value=1, max_value=50,
                               value=5, step=1, key="hw_quantity")
    st.markdown("**Niveaux**")
    lev_l, lev_r = st.columns(2)
    with lev_l:
        level_min = st.selectbox("Niveau minimum", [1, 2, 3, 4], index=0, key="hw_level_min")
    with lev_r:
        level_max = st.selectbox("Niveau maximum", [1, 2, 3, 4], index=1, key="hw_level_max")
    due = st.date_input("Date de remise", value=date.today() + timedelta(days=7),
                        min_value=date.today(), key="hw_due_date")

    st.markdown('<div style="height:6px;"></div>', unsafe_allow_html=True)
    col_cancel, col_submit = st.columns(2)
    with col_cancel:
        if st.button("Annuler", key="dlg_hw_cancel", use_container_width=True):
            st.rerun()
    with col_submit:
        if st.button("Assigner", key="dlg_hw_submit", use_container_width=True):
            if level_min > level_max:
                st.session_state["hw_dialog_error"] = "Le niveau minimum ne peut pas dépasser le niveau maximum."
                st.rerun()
            else:
                desc  = f"exercice{'s' if quantity > 1 else ''} au {tense.lower()}"
                color = {"Indicatif": "#f5c89a", "Subjonctif": "#c9b8e8",
                         "Conditionnel": "#a8d8c8", "Impératif": "#e8a8b8"}.get(mood, "#ccd7f0")
                conn = get_db()
                conn.execute("""
                    INSERT INTO homework
                        (class_id, description, mood, tense, due_date,
                         level_min, level_max, total_req, color)
                    VALUES (?,?,?,?,?,?,?,?,?)
                """, (class_id, desc, mood, tense, due.isoformat(),
                      level_min, level_max, int(quantity), color))
                conn.commit()
                conn.close()
                st.rerun()


@st.dialog("Modifier le devoir", width="large")
def _dialog_edit_homework(user, class_id, hw, members):
    """Edit a homework task or cancel it, plus view per-student progress."""

    mood_list  = list(MOODS.keys())
    cur_mood   = hw.get("mood") or mood_list[0]
    cur_tense  = hw.get("tense") or MOODS[cur_mood][0]
    cur_qty    = hw.get("total_req", 5)
    cur_lmin   = hw.get("level_min", 1)
    cur_lmax   = hw.get("level_max", 2)
    try:
        cur_due = date.fromisoformat(hw["due_date"])
    except Exception:
        cur_due = date.today() + timedelta(days=7)

    if st.session_state.get("edit_hw_error"):
        st.error(st.session_state.pop("edit_hw_error"))

    edit_col, prog_col = st.columns([1, 1], gap="large")

    with edit_col:
        st.markdown("#### ✏️ Modifier")
        mood  = st.selectbox("Type de conjugaison", mood_list,
                             index=mood_list.index(cur_mood) if cur_mood in mood_list else 0,
                             key="edit_hw_mood")
        tense_list = MOODS[mood]
        tense = st.selectbox("Temps", tense_list,
                             index=tense_list.index(cur_tense) if cur_tense in tense_list else 0,
                             key="edit_hw_tense")
        quantity = st.number_input("Nombre d'exercices", min_value=1, max_value=50,
                                   value=int(cur_qty), step=1, key="edit_hw_qty")
        st.markdown("**Niveaux**")
        ll, lr = st.columns(2)
        with ll:
            level_min = st.selectbox("Niveau minimum", [1,2,3,4],
                                     index=cur_lmin-1, key="edit_hw_lmin")
        with lr:
            level_max = st.selectbox("Niveau maximum", [1,2,3,4],
                                     index=cur_lmax-1, key="edit_hw_lmax")
        due = st.date_input("Date de remise", value=cur_due, key="edit_hw_due")

        st.markdown('<div style="height:8px;"></div>', unsafe_allow_html=True)
        save_col, cancel_col = st.columns(2)
        with save_col:
            if st.button("💾 Enregistrer", key="edit_hw_save", use_container_width=True):
                if level_min > level_max:
                    st.session_state["edit_hw_error"] = "Le niveau minimum ne peut pas dépasser le niveau maximum."
                    st.rerun()
                else:
                    update_homework(hw["id"], mood, tense, int(quantity),
                                    level_min, level_max, due.isoformat())
                    st.rerun()
        with cancel_col:
            if st.button("🗑 Annuler le devoir", key="edit_hw_delete", use_container_width=True):
                delete_homework(hw["id"])
                st.rerun()

    with prog_col:
        st.markdown("#### 📊 Progression des élèves")
        progress = get_homework_progress(hw["id"], class_id)
        if not progress:
            st.markdown('<div style="color:#999;font-size:1.1rem;">Aucun élève inscrit.</div>',
                        unsafe_allow_html=True)
        else:
            total_req = hw["total_req"]
            rows_html = ""
            for p in progress:
                name  = f"{p['first_name']} {p['last_name']}"
                done  = p["done"]
                pct   = min(done / total_req, 1.0) if total_req else 0
                bar_w = int(pct * 100)
                label = f"{done}/{total_req}"
                complete = pct >= 1.0
                bar_color = "#8a9ab5" if not complete else "#7bbf7b"
                rows_html += f"""
                <div style="margin-bottom:10px;">
                  <div style="display:flex;justify-content:space-between;
                              font-size:1.05rem;color:#2d2d2d;margin-bottom:3px;">
                    <span>{name}</span>
                    <span style="color:{'#4a9a4a' if complete else '#888'};">{label}</span>
                  </div>
                  <div style="background:#e8ecf4;border-radius:6px;height:8px;overflow:hidden;">
                    <div style="width:{bar_w}%;background:{bar_color};height:100%;
                                border-radius:6px;transition:width 0.3s;"></div>
                  </div>
                </div>"""
            st.markdown(
                f'<div style="max-height:340px;overflow-y:auto;padding-right:6px;">'
                f'{rows_html}</div>',
                unsafe_allow_html=True
            )

    st.markdown("""
    <style>
    .st-key-edit_hw_save .stButton > button {
        background: #8a9ab5 !important; color: #fff !important;
        border: none !important; border-radius: 10px !important; font-weight: 700 !important;
    }
    .st-key-edit_hw_save .stButton > button:hover { background: #7a8ba6 !important; }
    .st-key-edit_hw_delete .stButton > button {
        background: transparent !important; border: 1.5px solid #e8a0a0 !important;
        color: #c94444 !important; border-radius: 10px !important; font-weight: 700 !important;
    }
    .st-key-edit_hw_delete .stButton > button:hover { background: #fdeaea !important; }
    </style>
    """, unsafe_allow_html=True)


@st.dialog("Tableau de la classe", width="large")
def _dialog_class_stats(class_id, members):
    """Per-tense accuracy averages across all students in the class."""
    student_ids = [m["id"] for m in members]
    if not student_ids:
        st.info("Aucun élève dans cette classe.")
        return

    conn = get_db()
    placeholders = ",".join("?" * len(student_ids))
    rows = conn.execute(
        f"""SELECT user_id, mood, tense,
                   SUM(correct) AS correct, COUNT(*) AS total
            FROM exercise_log
            WHERE user_id IN ({placeholders})
            GROUP BY user_id, mood, tense""",
        student_ids
    ).fetchall()
    conn.close()

    from collections import defaultdict
    agg = defaultdict(lambda: [0, 0])
    for r in rows:
        agg[(r["mood"], r["tense"])][0] += r["correct"]
        agg[(r["mood"], r["tense"])][1] += r["total"]

    MOODS_LOCAL = {
        "Indicatif":    ["Présent","Passé composé","Imparfait","Plus-que-parfait",
                         "Passé simple","Passé antérieur","Futur simple","Futur antérieur"],
        "Subjonctif":   ["Présent","Passé","Imparfait","Plus-que-parfait"],
        "Conditionnel": ["Présent","Passé première forme","Passé deuxième forme"],
        "Impératif":    ["Présent","Passé"],
    }

    n = len(student_ids)
    s = "s" if n > 1 else ""

    left_col, right_col = st.columns([1, 1.2], gap="large")

    # ── Left: tense bars ─────────────────────────────────────────────────────
    with left_col:
        st.markdown(f"*Moyenne de précision · {n} élève{s}*")
        st.markdown("---")
        any_data = False
        for mood, tenses in MOODS_LOCAL.items():
            mood_rows = []
            for tense in tenses:
                c, t = agg.get((mood, tense), [0, 0])
                if t > 0:
                    pct = round(c / t * 100)
                    mood_rows.append((tense, pct))
            if mood_rows:
                any_data = True
                st.markdown(f"**{mood}**")
                for tense, pct in mood_rows:
                    bar_color = "#8fa8d8" if pct >= 70 else "#f0a070" if pct >= 40 else "#e07a7a"
                    st.markdown(
                        f"<div style='display:flex;align-items:center;gap:10px;margin-bottom:6px;'>"
                        f"<div style='width:170px;font-size:0.95rem;color:#2d2d2d;flex-shrink:0;'>{tense}</div>"
                        f"<div style='flex:1;background:#eee;border-radius:6px;height:10px;overflow:hidden;'>"
                        f"<div style='width:{pct}%;background:{bar_color};height:100%;border-radius:6px;'></div>"
                        f"</div>"
                        f"<div style='width:40px;text-align:right;font-size:0.95rem;color:#555;'>{pct}%</div>"
                        f"</div>",
                        unsafe_allow_html=True
                    )
                st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)
        if not any_data:
            st.markdown("<div style='color:#999;margin-top:20px;'>Aucun exercice complété.</div>",
                        unsafe_allow_html=True)

    # ── Right: average-over-time chart ───────────────────────────────────────
    with right_col:
        st.markdown("*Précision moyenne dans le temps*")
        st.markdown("---")

        # Colored checkbox CSS for class chart (keys: class_cb_{mi}_{ti})
        class_cb_css_rules = []
        for mi, mood in enumerate(MOODS_LOCAL.keys()):
            for ti, tense in enumerate(MOODS_LOCAL[mood]):
                label = MOOD_ABBREV.get(mood, mood[:3]) + " " + tense
                color = SERIES_COLOR.get(label, "#8fa8d8")
                class_cb_css_rules.append(
                    f'.st-key-class_cb_{mi}_{ti} label:has(input:checked) > '
                    f'span:first-of-type {{ background-color: {color} !important; '
                    f'border-color: {color} !important; }}'
                )
        st.markdown("<style>" + "\n".join(class_cb_css_rules) + "</style>",
                    unsafe_allow_html=True)

        # Mood tabs — st.tabs never triggers a rerun so dialog stays open
        tabs = st.tabs(list(MOODS_LOCAL.keys()))
        selected_pairs = []
        for mi, (tab, mood) in enumerate(zip(tabs, MOODS_LOCAL.keys())):
            with tab:
                tenses = MOODS_LOCAL[mood]
                tcols = st.columns(2)
                for ti, tense in enumerate(tenses):
                    with tcols[ti % 2]:
                        if st.checkbox(tense, key=f"class_cb_{mi}_{ti}"):
                            selected_pairs.append((mood, tense))

        range_label = st.session_state.get("class_chart_range", "1M")
        days = TIME_RANGES[range_label]
        chart_data = get_class_chart_data(student_ids, days) if selected_pairs else pd.DataFrame()

        if not chart_data.empty and selected_pairs:
            wanted = {MOOD_ABBREV.get(m, m) + " " + t for m, t in selected_pairs}
            chart_data = chart_data[chart_data["Temps"].isin(wanted)]

        end   = pd.Timestamp(datetime.now().date())
        start = end - pd.Timedelta(days=days) if days else end - pd.Timedelta(days=180)

        fr_months = ("['Jan','Fév','Mar','Avr','Mai','Jun',"
                     "'Jul','Aoû','Sep','Oct','Nov','Déc']"
                     "[month(datum.value)]"
                     " + ' ' + timeFormat(datum.value, '%d')")
        x_axis_kwargs = dict(title=None, labelExpr=fr_months, grid=False)
        y_axis = alt.Y("Précision:Q",
                       scale=alt.Scale(domain=[0, 100]),
                       axis=alt.Axis(title=None, values=[0, 25, 50, 75, 100],
                                     labelExpr="datum.value + '%'"))

        def style_chart(c):
            dark = bool(st.session_state.get("dark_mode"))
            bg   = "#1c1f26" if dark else "#ffffff"
            lab  = "#aab0bd" if dark else "#777"
            grid = "#2c313b" if dark else "#e3e3e3"
            dom  = "#3a3f49" if dark else "#cccccc"
            return (c.properties(height=200, background=bg,
                                  padding={"left":8,"right":8,"top":8,"bottom":8})
                     .configure_view(strokeWidth=0)
                     .configure_axis(labelFont="Dongle", labelFontSize=18,
                                     labelColor=lab, gridColor=grid,
                                     domainColor=dom, tickColor=dom))

        if chart_data.empty:
            empty_df = pd.DataFrame({"Jour":[start,end],"Précision":[None,None]})
            chart = style_chart(
                alt.Chart(empty_df).mark_line().encode(
                    x=alt.X("Jour:T", scale=alt.Scale(domain=[start,end]),
                             axis=alt.Axis(**x_axis_kwargs)),
                    y=y_axis))
        else:
            present = [s for s in SERIES_ORDER if s in set(chart_data["Temps"].unique())]
            color_scale = alt.Scale(domain=present,
                                    range=[SERIES_COLOR[s] for s in present])
            chart = style_chart(
                alt.Chart(chart_data).mark_line(strokeWidth=2.5, interpolate="monotone",
                                                 strokeCap="round").encode(
                    x=alt.X("Jour:T", scale=alt.Scale(domain=[start,end]),
                             axis=alt.Axis(**x_axis_kwargs)),
                    y=y_axis,
                    color=alt.Color("Temps:N", scale=color_scale, legend=None),
                    tooltip=["Temps",
                             alt.Tooltip("Jour:T", format="%d %b %Y", formatType="time"),
                             alt.Tooltip("Précision:Q", format=".1f")]))

        st.altair_chart(chart, use_container_width=True, theme=None)

        _, mid, _ = st.columns([1, 2, 1])
        with mid:
            st.segmented_control(
                "Période", list(TIME_RANGES.keys()),
                default="1M", key="class_chart_range",
                label_visibility="collapsed"
            )


@st.dialog("Supprimer la classe")
def _dialog_delete_class(user, class_id, class_name):
    """Confirmation dialog before permanently deleting a class."""
    st.markdown(f"""
    <div style="text-align:center;margin-bottom:6px;">
        <div style="font-size:2.6rem;margin-bottom:8px;">🗑️</div>
        <div style="font-size:1.25rem;color:#2d2d2d;font-weight:600;margin-bottom:6px;">
            Voulez-vous vraiment supprimer <em>{class_name}</em> ?
        </div>
        <div style="font-size:1.05rem;color:#999;line-height:1.5;">
            Cette action est <strong>irréversible</strong>.<br>
            Tous les devoirs et les membres seront retirés.
        </div>
    </div>
    """, unsafe_allow_html=True)
    st.markdown('<div style="height:10px;"></div>', unsafe_allow_html=True)

    error = st.session_state.get("delete_class_error")
    if error:
        st.error(error)

