def render_grammaire(user):
    st.markdown(grammaire_css(), unsafe_allow_html=True)
    mode = st.session_state.get("gr_mode", "settings")
    if mode == "exercise":
        _render_exercise(user)
    elif mode == "results":
        _render_results(user)
    else:
        _render_settings(user)


def _render_settings(user):
    ss = st.session_state
    ss.setdefault("gr_level", 1)
    ss.setdefault("gr_vmode", "all")
    ss.setdefault("gr_mood", "Indicatif")
    ss.setdefault("gr_pronouns", {i: True for i in range(6)})
    ss.setdefault("gr_tenses", {})
    ss.setdefault("gr_selected_verbs", {})
    ss.setdefault("gr_show_tense", False)

    is_guest = ss.get("is_guest")
    show_verbpanel = (ss.gr_vmode == "sel") and not is_guest

    if ss.get("gr_build_error"):
        st.error(ss.pop("gr_build_error"))

    if show_verbpanel:
        main_col, panel_col = st.columns([1.5, 1], gap="large")
    else:
        main_col = st.container()
        panel_col = None

    with main_col:
        st.markdown('<div class="gr-h">Réglages</div>', unsafe_allow_html=True)

        # ── Niveau ────────────────────────────────────────────────────
        lab, l1, l2, l3, l4 = st.columns([2, 1, 1, 1, 1])
        with lab:
            st.markdown('<div class="gr-label">Niveau</div>', unsafe_allow_html=True)
        for lvl, c in zip((1, 2, 3, 4), (l1, l2, l3, l4)):
            with c:
                if ss.gr_level == lvl:
                    st.markdown(
                        f'<div style="width:46px;height:46px;border-radius:50%;'
                        f'background:#b7e6a8;display:flex;align-items:center;'
                        f'justify-content:center;font-size:1.5rem;font-weight:700;'
                        f'color:#2d4d22;">{lvl}</div>', unsafe_allow_html=True)
                else:
                    if st.button(str(lvl), key=f"lvl_{lvl}"):
                        ss.gr_level = lvl
                        st.rerun()

        # ── Verbes inclus (Tous / Sélection) with active highlight ────
        st.markdown('<div class="gr-label">Verbes inclus</div>', unsafe_allow_html=True)
        green = "background:#b7e6a8 !important;border-color:#9ed98f !important;color:#2d4d22 !important;"
        which = "vmode_all" if ss.gr_vmode == "all" else "vmode_sel"
        st.markdown(f"<style>.st-key-{which} .stButton > button{{{green}}}</style>",
                    unsafe_allow_html=True)
        vc1, vc2 = st.columns(2)
        with vc1:
            if st.button("Tous les verbes", key="vmode_all"):
                ss.gr_vmode = "all"; st.rerun()
        with vc2:
            if st.button("Sélection", key="vmode_sel", disabled=is_guest):
                ss.gr_vmode = "sel"; st.rerun()

        # ── Pronoms | Temps des verbes ────────────────────────────────
        pcol, tcol = st.columns(2)
        with pcol:
            st.markdown('<div class="gr-sub">Pronoms</div>', unsafe_allow_html=True)
            for i, lab_p in enumerate(conj.PRONOUN_LABELS):
                wkey = f"gr_pron::{i}"
                if wkey not in ss:
                    ss[wkey] = True  # default all pronouns ON (first render only)
                ss.gr_pronouns[i] = st.checkbox(lab_p.capitalize(), key=wkey)
        with tcol:
            st.markdown('<div class="gr-sub">Temps des verbes</div>', unsafe_allow_html=True)
            m1, m2 = st.columns(2)
            moods = list(MOODS.keys())
            active_idx = moods.index(ss.gr_mood) if ss.gr_mood in moods else 0
            st.markdown(
                f"<style>.st-key-grmood_{active_idx} .stButton > button"
                f"{{background:#ccd7f0 !important;border-color:#b8c4e0 !important;}}</style>",
                unsafe_allow_html=True)
            for idx, mood in enumerate(moods):
                tgt = m1 if idx % 2 == 0 else m2
                with tgt:
                    if st.button(mood, key=f"grmood_{idx}"):
                        ss.gr_mood = mood; st.rerun()
            # Tense checkboxes for the active mood. The checkbox's own keyed
            # state is the single source of truth (no parallel dict to desync).
            # All tenses default OFF.
            for t in MOODS[ss.gr_mood]:
                wkey = f"grtense::{ss.gr_mood}::{t}"
                checked = st.checkbox(t, key=wkey)
                ss.gr_tenses[(ss.gr_mood, t)] = checked

        # ── Option: show tense beside each verb in the question ───────
        if ss.gr_level >= 2:
            ss.gr_show_tense = st.checkbox(
                "Afficher le temps à côté de chaque verbe",
                value=ss.get("gr_show_tense", False), key="gr_show_tense_cb")

        # ── Commencer ─────────────────────────────────────────────────
        # Scan ALL tense checkbox widget keys directly (across every mood),
        # so selection is exactly what's checked — no stale dict entries.
        selected_pairs = []
        for m, tenses in MOODS.items():
            for t in tenses:
                if ss.get(f"grtense::{m}::{t}", False):
                    selected_pairs.append((m, t))
        sel_pron = [i for i, v in ss.gr_pronouns.items() if v]
        ready = bool(selected_pairs) and bool(sel_pron)
        if ready:
            st.markdown(
                "<style>.st-key-gr_start .stButton > button{background:#8a9ab5 !important;}</style>",
                unsafe_allow_html=True)
        if st.button("Commencer", key="gr_start", disabled=not ready):
            _begin_exercise(user, selected_pairs, sel_pron)

    if show_verbpanel and panel_col is not None:
        with panel_col:
            _render_verb_panel(user)


def _render_verb_panel(user):
    ss = st.session_state
    st.markdown('<div class="gr-verbpanel-title">Verbes</div>', unsafe_allow_html=True)

    # Default pool for the level + the user's added verbs, ALPHABETISED
    pool = sorted(set(
        conj.DEFAULT_VERBS.get(ss.gr_level, []) + get_user_verbs(user["id"])))
    if not pool:
        st.markdown('<div style="color:#999;">Aucun verbe. Ajoutez-en ci-dessous.</div>',
                    unsafe_allow_html=True)
    for v in pool:
        ss.gr_selected_verbs[v] = st.checkbox(
            v, value=ss.gr_selected_verbs.get(v, True), key=f"selverb_{v}")

    st.markdown('<div style="height:10px;"></div>', unsafe_allow_html=True)
    add_c, btn_c = st.columns([4, 1])
    with add_c:
        new_v = st.text_input("Ajouter un verbe", key="gr_add_verb",
                              label_visibility="collapsed",
                              placeholder="ajouter un verbe…")
    with btn_c:
        if st.button("➕", key="gr_add_btn"):
            ok, msg = add_user_verb(user["id"], new_v)
            if ok:
                ss.gr_selected_verbs[new_v.strip().lower()] = True
                ss.pop("gr_add_verb", None)
            else:
                ss.gr_verb_err = msg
            st.rerun()
    if ss.get("gr_verb_err"):
        st.error(ss.pop("gr_verb_err"))


def _begin_exercise(user, selected_pairs, sel_pron):
    ss = st.session_state
    if ss.gr_vmode == "sel" and not ss.get("is_guest"):
        verbs = [v for v, on in ss.gr_selected_verbs.items() if on]
        if not verbs:
            verbs = conj.DEFAULT_VERBS.get(ss.gr_level, [])
    else:
        verbs = conj.DEFAULT_VERBS.get(ss.gr_level, [])

    with st.spinner("Préparation des exercices…"):
        questions = conj.make_exercise(
            ss.gr_level, verbs, sel_pron, selected_pairs, n=12,
            show_tense=ss.get("gr_show_tense", False))

    if not questions:
        diag = conj.library_diagnostic("manger")
        ss.gr_build_error = (
            "Impossible de générer des exercices. État de la conjugaison : "
            f"{diag}. (Vérifiez « pip3 install verbecc », ou réessayez : le "
            "premier appel entraîne le modèle et peut prendre ~1 min.)")
        st.rerun()
        return
    ss.gr_questions = questions
    ss.gr_idx = 0
    ss.gr_results = []
    ss.gr_checked = None
    ss.gr_exercise_level = ss.gr_level          # level this exercise was run at
    ss.gr_exercise_pairs = list(selected_pairs)  # the exact (mood,tense) set chosen
    ss.pop("gr_rewarded", None)
    ss.pop("gr_reward_amount", None)
    ss.gr_mode = "exercise"
    st.rerun()


def _render_exercise(user):
    ss = st.session_state
    qs = ss.get("gr_questions", [])
    idx = ss.get("gr_idx", 0)
    if not qs or idx >= len(qs):
        ss.gr_mode = "results"; st.rerun(); return
    q = qs[idx]

    # Center everything in a comfortable column so the answer box and buttons
    # don't stretch the full page width.
    _, mid, _ = st.columns([1, 4, 1])
    with mid:
        st.markdown(f'<div class="ex-progress">Question {idx+1} / {len(qs)}</div>',
                    unsafe_allow_html=True)
        st.progress(idx / len(qs))
        st.markdown('<div style="height:18px;"></div>', unsafe_allow_html=True)
        st.markdown(q["prompt_html"], unsafe_allow_html=True)
        st.markdown('<div style="height:14px;"></div>', unsafe_allow_html=True)

        checked = ss.get("gr_checked")
        n_blanks = q["blanks"]

        answers_in = []
        for b in range(n_blanks):
            val = st.text_input(
                f"Réponse {b+1}" if n_blanks > 1 else "Votre réponse",
                key=f"gr_ans_{idx}_{b}", disabled=checked is not None,
                placeholder="tapez votre réponse (avec ou sans le pronom)…")
            answers_in.append(val)

        # accent helper buttons (two rows) → append to the first answer box
        st.markdown('<div style="font-size:1.15rem;color:#999;margin:14px 0 4px;">Accents :</div>',
                    unsafe_allow_html=True)
        half = (len(ACCENT_CHARS) + 1) // 2
        for row_chars, row_start in ((ACCENT_CHARS[:half], 0),
                                     (ACCENT_CHARS[half:], half)):
            acc_cols = st.columns(half)
            for j, ch in enumerate(row_chars):
                with acc_cols[j]:
                    if st.button(ch, key=f"acc_{idx}_{row_start+j}",
                                 disabled=checked is not None):
                        k = f"gr_ans_{idx}_0"
                        ss[k] = (ss.get(k, "") or "") + ch
                        st.rerun()

        st.markdown('<div style="height:22px;"></div>', unsafe_allow_html=True)

        if checked is None:
            if st.button("Vérifier", key="gr_check", use_container_width=True):
                accept = q.get("accept") or [None] * n_blanks
                per_blank = []
                for b in range(n_blanks):
                    ok_b = conj.grade_answer(
                        answers_in[b], q["answers"][b],
                        accept=accept[b] if b < len(accept) else None)
                    per_blank.append(ok_b)
                correct = all(per_blank)
                ss.gr_checked = (correct, q["answers"])
                # Record (mood, tense, correct) for EACH blank so multi-tense
                # questions feed every tense they contain.
                meta = q.get("meta", {})
                blanks_data = []
                if meta.get("specs"):
                    for bi, spec in enumerate(meta["specs"]):
                        bmood, btense = spec[1], spec[2]
                        ok_b = per_blank[bi] if bi < len(per_blank) else correct
                        blanks_data.append({"mood": bmood, "tense": btense,
                                            "correct": ok_b})
                elif meta.get("mood"):
                    blanks_data.append({"mood": meta.get("mood"),
                                        "tense": meta.get("tense"),
                                        "correct": correct})
                ss.gr_results.append({
                    "correct": correct,
                    "blanks": blanks_data,
                })
                st.rerun()
        else:
            correct, expected = checked
            if correct:
                st.markdown('<div class="ex-result-ok">✓ Correct !</div>',
                            unsafe_allow_html=True)
            else:
                shown = " · ".join(str(e) for e in expected)
                st.markdown(
                    f'<div class="ex-result-no">La bonne réponse : '
                    f'<strong>{shown}</strong></div>', unsafe_allow_html=True)
            nxt = "Question suivante" if idx + 1 < len(qs) else "Voir les résultats"
            if st.button(nxt, key="gr_next", use_container_width=True):
                ss.gr_idx = idx + 1
                ss.gr_checked = None
                st.rerun()

        st.markdown('<div style="height:10px;"></div>', unsafe_allow_html=True)
        if st.button("Quitter l'exercice", key="gr_quit"):
            for k in ("gr_questions", "gr_idx", "gr_results", "gr_checked"):
                ss.pop(k, None)
            ss.gr_mode = "settings"
            st.rerun()


def _render_results(user):
    ss = st.session_state
    results = ss.get("gr_results", [])
    total = len(results)
    correct = sum(1 for r in results if r["correct"])

    if not ss.get("gr_rewarded"):
        if not ss.get("is_guest") and total > 0:
            reward = random.randint(100, 250)
            level = ss.get("gr_exercise_level", ss.get("gr_level", 1))
            pairs = ss.get("gr_exercise_pairs", [])
            summary = complete_exercise(user["id"], results, reward,
                                        level, pairs)
            refresh_user()
            ss.gr_reward_amount = reward
            ss.gr_devoir_credit = summary.get("devoirs_credited", [])
        ss.gr_rewarded = True

    st.markdown('<div class="gr-h" style="text-align:center;">Exercice terminé !</div>',
                unsafe_allow_html=True)
    st.markdown(
        f'<div style="font-size:3rem;font-weight:800;color:#2d2d2d;text-align:center;">{correct} / {total}</div>',
        unsafe_allow_html=True)
    pct = round(correct / total * 100) if total else 0
    st.markdown(f'<div style="font-size:1.4rem;color:#8fa8d8;font-weight:700;text-align:center;">{pct}% de réussite</div>',
                unsafe_allow_html=True)
    if ss.get("gr_reward_amount"):
        st.markdown(
            f'<div style="font-size:1.6rem;margin-top:14px;text-align:center;">📚 +{ss.gr_reward_amount} pages</div>',
            unsafe_allow_html=True)
        n_credit = len(ss.get("gr_devoir_credit", []))
        if n_credit:
            st.markdown(
                f'<div style="font-size:1.3rem;margin-top:6px;text-align:center;color:#6b8f5e;">'
                f'✓ {n_credit} devoir{"s" if n_credit > 1 else ""} mis à jour</div>',
                unsafe_allow_html=True)
    elif ss.get("is_guest"):
        st.markdown('<div style="font-size:1.2rem;color:#999;margin-top:10px;text-align:center;">'
                    'Connectez-vous pour gagner des pages.</div>', unsafe_allow_html=True)

    b1, b2 = st.columns(2)
    with b1:
        if st.button("Nouvel exercice", key="gr_again", use_container_width=True):
            for k in ("gr_questions", "gr_idx", "gr_results", "gr_checked",
                      "gr_rewarded", "gr_reward_amount"):
                ss.pop(k, None)
            ss.gr_mode = "settings"
            st.rerun()
    with b2:
        if st.button("Retour au profil", key="gr_done", use_container_width=True):
            for k in ("gr_questions", "gr_idx", "gr_results", "gr_checked",
                      "gr_rewarded", "gr_reward_amount"):
                ss.pop(k, None)
            ss.gr_mode = "settings"
            ss.nav = "profil"
            st.rerun()


