# Per-character LOCAL odds (within a single pull, tier distribution). The GLOBAL
# odds = local tier odds ÷ number of characters (uniform character pick).
_TIER_PCT = {1: 76.0, 2: 20.0, 3: 4.0}

def _static_png_data_uri(path):
    """Inline local PNGs for Streamlit component iframes."""
    try:
        with open(path, "rb") as fh:
            data = _b64mod.b64encode(fh.read()).decode("ascii")
        return f"data:image/png;base64,{data}"
    except OSError:
        return ""

