def _odds_table_html(mode):
    """mode 'locale' = per-character tier odds; 'globale' = ÷6 (uniform char)."""
    n = len(CHAR_KEYS)
    rows = []
    for key in CHAR_KEYS:
        name = CHAR_NAMES.get(key, key)
        if mode == "locale":
            i, ii, iii = _TIER_PCT[1], _TIER_PCT[2], _TIER_PCT[3]
            share = f"1/{n}"
            cells = (f'<td class="num">{share}</td>'
                     f'<td class="num">{i:.0f}%</td>'
                     f'<td class="num">{ii:.0f}%</td>'
                     f'<td class="num">{iii:.0f}%</td>')
            head_share = "<th></th>"
        else:
            i, ii, iii = (_TIER_PCT[1]/n, _TIER_PCT[2]/n, _TIER_PCT[3]/n)
            cells = (f'<td class="num">{i:.1f}%</td>'
                     f'<td class="num">{ii:.1f}%</td>'
                     f'<td class="num">{iii:.1f}%</td>')
            head_share = ""
        rows.append(f'<tr><td class="name">{name}</td>{cells}</tr>')
    head = (f'<tr><th></th>{head_share}<th>I</th><th>II</th><th>III</th></tr>'
            if mode == "locale" else
            '<tr><th></th><th>I</th><th>II</th><th>III</th></tr>')
    return (f'<div class="rl-odds"><table>{head}'
            + "".join(rows) + '</table></div>')

def _odds_floating_html(mode):
    return f'<div class="rl-odds-float">{_odds_table_html(mode)}</div>'

def _gacha_animation_html(results):
    """A self-contained reveal: the book sprite speeds up, the screen gradually
    lights to white, settles back, then rolled character icons briefly appear.
    Runs entirely in the browser (no Streamlit reruns interrupt it).
    All media is inlined so it resolves inside the component iframe."""
    # Build the sequence of character icons to reveal (data URI + tier ring)
    tier_color = {tier: frame["border"] for tier, frame in TIER_FRAMES.items()}
    cards = []
    for r in results:
        cid = f'{r["char"]}_{r["tier"]}'
        ring = tier_color[r["tier"]]
        src = _static_png_data_uri(f"static/characters/{cid}.png")
        img = (f'<img src="{src}" alt="">' if src
               else '<div class="missing-char"></div>')
        name = _html.escape(str(r["name"]))
        tier = ["", "I", "II", "III"][r["tier"]]
        dup = " &middot; doublon" if r["dup"] else ""
        cards.append(
            f'<div class="reveal-card" style="--ring:{ring}">'
            f'{img}'
            f'<div class="rc-name">{name} '
            f'<span class="rc-tier">{tier}</span>{dup}</div>'
            f'</div>')
    cards_html = "".join(cards)
    n = len(results)
    book_b64 = _BOOK_SPRITE_B64  # inlined webm, assigned at module load
    return f"""
<div id="stage">
<video id="book" src="data:video/webm;base64,{book_b64}"
  autoplay loop muted playsinline
  style="width:min(930px, 70vw);height:min(620px, 48vw);object-fit:contain;"></video>
<div id="flash"></div>
<div id="reveal">{cards_html}</div>
</div>
<style>
html,body{{margin:0;background:transparent;}}
#stage{{position:relative;height:500px;display:flex;align-items:center;justify-content:center;overflow:hidden;background:transparent;}}
#book{{transform-origin:center;animation:bookIdle 1.6s ease-in-out infinite;background:transparent;}}
#flash{{position:absolute;inset:0;background:#fff;opacity:0;pointer-events:none;animation:flash 5.4s ease-in-out forwards;}}
@keyframes bookIdle{{0%,100%{{transform:translateY(0) scale(1);}}50%{{transform:translateY(-4px) scale(1.01);}}}}
@keyframes flash{{0%,26%{{opacity:0;}}54%{{opacity:1;}}72%{{opacity:.98;}}88%{{opacity:0;}}100%{{opacity:0;}}}}
#reveal{{position:absolute;inset:0;display:flex;flex-wrap:wrap;gap:18px;align-items:center;justify-content:center;opacity:0;animation:showHoldFade 3.2s ease-in-out 2.6s forwards;}}
.reveal-card{{display:flex;flex-direction:column;align-items:center;gap:8px;}}
.reveal-card img,.missing-char{{width:{150 if n==1 else 104}px;height:{150 if n==1 else 104}px;border-radius:50%;object-fit:cover;border:5px solid var(--ring);box-shadow:0 5px 18px rgba(80,90,120,0.25);background:#eef0f6;}}
.rc-name{{font-size:{1.45 if n==1 else 1.05}rem;font-weight:800;color:#2d2d2d;text-align:center;}}
.rc-tier{{color:#8a8a8a;font-weight:800;}}
@keyframes showHoldFade{{0%{{opacity:0;transform:scale(.82);}}24%,68%{{opacity:1;transform:scale(1);}}100%{{opacity:0;transform:scale(.96);}}}}
</style>
<script>
(function(){{
  var vid=document.getElementById('book');
  function play() {{
    var p = vid.play();
    if (p && p.catch) {{ p.catch(function(){{}}); }}
  }}
  vid.playbackRate=0.85;
  play();
  // The book itself stays still; only the sprite playback speed changes.
  setTimeout(function(){{
    vid.style.animation='none';
    var t=0;
    var ramp=setInterval(function(){{
      t+=80;
      var rate=Math.min(1.15+t/420,4.8);
      vid.playbackRate=rate;
      if(t>=1800){{clearInterval(ramp);}}
    }},80);
  }},520);
  setTimeout(function(){{
    vid.playbackRate=0.9;
    vid.style.animation='bookIdle 1.6s ease-in-out infinite';
  }},4300);
}})();
</script>
"""

def render_rouler(user):
    ss = st.session_state
    st.markdown(_rouler_css(), unsafe_allow_html=True)
    ss.setdefault("rl_odds_mode", "locale")
    ss.setdefault("rl_odds_visible", False)

    if not user or user.get("id") is None:
        st.markdown('<h1 class="dash-title">Rouler</h1>', unsafe_allow_html=True)
        st.info("Connectez-vous pour accéder au gacha.")
        return

    pages = user["pages"] or 0
    pity = user.get("pity_counter", 0) or 0

    # ── Top-right balance + odds toggle ───────────────────────────────
    top_spacer, bal_col, help_col = st.columns([7, 1.6, 0.55])
    with bal_col:
        st.markdown(
            f'<div class="rl-balance"><span class="rl-stack"><span></span></span>{pages:,}</div>',
            unsafe_allow_html=True)
    with help_col:
        if st.button("?", key="rl_help"):
            ss.rl_odds_visible = not ss.rl_odds_visible
            st.rerun()

    if ss.rl_odds_visible:
        if st.button("Locale", key="rl_local",
                     type=("primary" if ss.rl_odds_mode == "locale" else "secondary")):
            ss.rl_odds_mode = "locale"
            st.rerun()
        if st.button("Globale", key="rl_global",
                     type=("primary" if ss.rl_odds_mode == "globale" else "secondary")):
            ss.rl_odds_mode = "globale"
            st.rerun()
        st.markdown(_odds_floating_html(ss.rl_odds_mode), unsafe_allow_html=True)

    # ── Main stage: fixed book position; odds float over it on request ──
    if ss.get("rl_animating"):
        components.html(_gacha_animation_html(ss.get("rl_last_results", [])),
                        height=500)
        ss.rl_animating = False
        ss.pop("rl_last_results", None)
    else:
        book_b64 = _BOOK_SPRITE_B64
        st.markdown(
            f'<div class="rl-stage-wrap"><div class="rl-book">'
            f'<video src="data:video/webm;base64,{book_b64}" '
            f'autoplay loop muted playsinline>'
            f'</video></div></div>',
            unsafe_allow_html=True)

    # ── Pity bar ──────────────────────────────────────────────────────
    pct = min(pity, PITY_THRESHOLD) / PITY_THRESHOLD * 100
    st.markdown(
        f'<div class="rl-pity-wrap"><div class="rl-pity-label">Garantie III</div>'
        f'<div class="rl-pity-track"><div class="rl-pity-fill" style="width:{pct:.0f}%;"></div>'
        f'<div class="rl-pity-text">{min(pity, PITY_THRESHOLD)}/{PITY_THRESHOLD}</div></div></div>',
        unsafe_allow_html=True)
    st.markdown('<div style="height:36px;"></div>', unsafe_allow_html=True)

    # ── Pull buttons ──────────────────────────────────────────────────
    is_guest = bool(ss.get("is_guest"))
    is_animating = bool(ss.get("rl_animating"))
    _, p1, p2, _ = st.columns([0.35, 1.18, 1.18, 0.35], gap="large")
    with p1:
        can1 = pages >= GACHA_COST[1] and not is_guest
        if st.button(f"{GACHA_COST[1]:,}\nInvocation ×1", key="rl_pull1",
                     use_container_width=True, disabled=(not can1 or is_animating)):
            _do_pull(user, 1)
    with p2:
        can10 = pages >= GACHA_COST[10] and not is_guest
        if st.button(f"{GACHA_COST[10]:,}\nInvocation ×10", key="rl_pull10",
                     use_container_width=True, disabled=(not can10 or is_animating)):
            _do_pull(user, 10)

    if is_guest:
        st.markdown('<div style="text-align:center;color:#999;font-size:1.1rem;margin-top:10px;">'
                    'Connectez-vous pour rouler.</div>', unsafe_allow_html=True)
    elif not (pages >= GACHA_COST[1]):
        st.markdown('<div style="text-align:center;color:#999;font-size:1.1rem;margin-top:10px;">'
                    'Pas assez de pages. Complétez des exercices pour en gagner !</div>',
                    unsafe_allow_html=True)

    # Show a small summary of the last pull's refunds, if any
    if ss.get("rl_last_summary") and not ss.get("rl_animating"):
        s = ss.rl_last_summary
        if s.get("refunded"):
            st.markdown(
                f'<div style="text-align:center;color:#6b8f5e;font-size:1.15rem;margin-top:8px;">'
                f'Doublons remboursés : +{s["refunded"]:,} pages</div>',
                unsafe_allow_html=True)

def _do_pull(user, count):
    ss = st.session_state
    summary = do_gacha_pull(user["id"], count)
    refresh_user()
    ss.rl_last_results = summary["results"]
    ss.rl_last_summary = summary
    ss.rl_animating = True
    st.rerun()


def render_placeholder(title, note):
    st.markdown(f'<h1 class="dash-title">{title}</h1>', unsafe_allow_html=True)
    st.info(note)

# ══════════════════════════════════════════════════════════════════════════════
# SETTINGS PAGE
# ══════════════════════════════════════════════════════════════════════════════

def safe_secret(section, key, default=""):
    try:
        return st.secrets.get(section, {}).get(key, default)
    except Exception:
        return default


TEACHER_CODE = safe_secret("app", "teacher_code")

def render_reglages(user):
    st.markdown('<h1 class="dash-title">Réglages</h1>', unsafe_allow_html=True)
    st.markdown("---")

    is_guest = bool(st.session_state.get("is_guest"))

    # ── Apparence (thème clair / sombre) ──────────────────────────────────────
    st.markdown("""
        <div style="margin-bottom:6px;">
            <span style="font-size:1.5rem;font-weight:700;">Apparence</span>
        </div>
        <div style="font-size:1.15rem;color:#888;margin-bottom:18px;">
            Basculer entre le thème clair et le thème sombre.
        </div>
    """, unsafe_allow_html=True)

    col_lbl, col_dark = st.columns([3, 1], gap="large")
    with col_lbl:
        st.markdown(
            '<div style="padding:10px 0;font-size:1.15rem;">🌙 Mode sombre</div>',
            unsafe_allow_html=True)
    with col_dark:
        st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)
        dark_on = st.toggle(
            "Mode sombre",
            value=bool(st.session_state.get("dark_mode")),
            key="dark_mode_toggle",
            label_visibility="collapsed"
        )
        if dark_on != bool(st.session_state.get("dark_mode")):
            st.session_state.dark_mode = dark_on
            # Persist for logged-in users (guests are session-only)
            if not is_guest and st.session_state.get("user"):
                conn = get_db()
                conn.execute("UPDATE users SET dark_mode=? WHERE id=?",
                             (1 if dark_on else 0, st.session_state.user["id"]))
                conn.commit()
                conn.close()
            st.rerun()

    st.markdown("---")

    # ── Teacher mode section (hidden in guest mode) ───────────────────────────
    if not is_guest:
        is_teacher = bool(user.get("is_teacher", 0))

        # code_verified is True if: already a teacher, or entered the code this session
        if "teacher_code_verified" not in st.session_state:
            st.session_state.teacher_code_verified = is_teacher

        code_verified = st.session_state.teacher_code_verified

        st.markdown("""
            <div style="margin-bottom:6px;">
                <span style="font-size:1.5rem;font-weight:700;">Mode enseignant</span>
            </div>
            <div style="font-size:1.15rem;color:#888;margin-bottom:18px;">
                Entrez le code d'accès pour activer ou désactiver le mode enseignant.
            </div>
        """, unsafe_allow_html=True)

        col_box, col_switch = st.columns([3, 1], gap="large")

        with col_box:
            if not code_verified:
                code_input = st.text_input(
                    "Code d'accès enseignant",
                    key="teacher_code_input",
                    placeholder="Entrez le code...",
                    label_visibility="collapsed"
                )
                if code_input == TEACHER_CODE:
                    conn = get_db()
                    conn.execute("UPDATE users SET is_teacher=1 WHERE id=?",
                                 (user["id"],))
                    conn.commit()
                    conn.close()
                    st.session_state.user = get_user_by_id(user["id"])
                    st.session_state.teacher_code_verified = True
                    st.session_state.pop("teacher_code_input", None)
                    st.rerun()
                elif code_input:
                    st.error("Code incorrect.")
            else:
                st.markdown(
                    '<div style="padding:10px 0;color:#7aab7a;font-size:1.15rem;">✓ Code vérifié — mode enseignant déverrouillé</div>',
                    unsafe_allow_html=True
                )

        with col_switch:
            st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)
            toggle = st.toggle(
                "Activer",
                value=is_teacher,
                disabled=not code_verified,
                key="teacher_toggle"
            )
            if code_verified and toggle != is_teacher:
                conn = get_db()
                conn.execute("UPDATE users SET is_teacher=? WHERE id=?",
                             (1 if toggle else 0, user["id"]))
                conn.commit()
                conn.close()
                st.session_state.user = get_user_by_id(user["id"])
                if not toggle:
                    st.session_state.teacher_code_verified = False
                st.rerun()

        st.markdown("---")


# ══════════════════════════════════════════════════════════════════════════════
# ROUTER
# ══════════════════════════════════════════════════════════════════════════════

if st.session_state.logged_in or st.session_state.is_guest:
    refresh_user()
    st.markdown(app_css(st.session_state.nav,
                        st.session_state.profile_view), unsafe_allow_html=True)
    render_sidebar()

    nav = st.session_state.nav
    if nav == "profil" and st.session_state.logged_in:
        # Teacher viewing a student's dashboard
        student_id = st.session_state.get("viewing_student_dash")
        if student_id and bool(st.session_state.user.get("is_teacher")):
            student = get_user_by_id(student_id)
            if student:
                if st.button("← Retour à la classe", key="back_from_student_dash"):
                    st.session_state.viewing_student_dash = None
                    st.session_state.nav = "classe"
                    st.rerun()
                render_profile_page(student)
            else:
                st.session_state.viewing_student_dash = None
                render_profile_page(st.session_state.user)
        else:
            render_profile_page(st.session_state.user)
    elif nav == "classe":
        render_classe_page(st.session_state.user)
    elif nav == "grammaire":
        render_grammaire(st.session_state.user if st.session_state.logged_in else {"id": None})
    elif nav == "rouler":
        render_rouler(st.session_state.user)
    elif nav == "reglages":
        render_reglages(st.session_state.user)
    else:
        # Guest landed on a restricted page somehow — send to Grammaire
        st.session_state.nav = "grammaire"
        st.rerun()

    # Dark overlay injected LAST (after page CSS) so it wins the cascade by
    # source order — page-level styles can no longer re-impose light colours.
    if st.session_state.get("dark_mode"):
        st.markdown(dark_mode_css(st.session_state.nav,
                                  st.session_state.profile_view), unsafe_allow_html=True)
else:
    st.markdown(AUTH_CSS, unsafe_allow_html=True)
    if st.session_state.page == "signup":
        render_signup()
    else:
        render_login()
